export const getPutMfaIdDisableQueryKey = (
  id: string,
  putMfaIdDisableBody?: BodyType<PutMfaIdDisableBody>,
) => {
  return ["PUT", `/mfa/${id}/disable`, putMfaIdDisableBody] as const;
};

export const getPutMfaIdDisableQueryOptions = <
  TData = Awaited<ReturnType<typeof putMfaIdDisable>>,
  TError = ErrorType<PutMfaIdDisable400 | PutMfaIdDisable404>,
>(
  id: string,
  putMfaIdDisableBody: BodyType<PutMfaIdDisableBody>,
  options?: {
    query?: Partial<
      UseQueryOptions<
        Awaited<ReturnType<typeof putMfaIdDisable>>,
        TError,
        TData
      >
    >;
    request?: SecondParameter<typeof customInstance>;
  },
) => {
  const { query: queryOptions, request: requestOptions } = options ?? {};

  const queryKey =
    queryOptions?.queryKey ??
    getPutMfaIdDisableQueryKey(id, putMfaIdDisableBody);

  const queryFn: QueryFunction<Awaited<ReturnType<typeof putMfaIdDisable>>> = ({
    signal,
  }) => putMfaIdDisable(id, putMfaIdDisableBody, requestOptions, signal);

  return {
    queryKey,
    queryFn,
    enabled: id !== null && id !== undefined,
    staleTime: 10000,
    ...queryOptions,
  } as UseQueryOptions<
    Awaited<ReturnType<typeof putMfaIdDisable>>,
    TError,
    TData
  > & { queryKey: DataTag<QueryKey, TData, TError> };
};

